import{_ as b,o as e,c as a,j as r,a as t,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"小东西","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/3.C级/小东西.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/3.C级/小东西.md"}'),d={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/3.C级/小东西.md"};function n(s,p,l,_,i,c){return e(),a("div",null,[...p[0]||(p[0]=[r("h1",{id:"小东西",tabindex:"-1"},[t("小东西 "),r("a",{class:"header-anchor",href:"#小东西","aria-label":'Permalink to "小东西"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"新世短歌037")])])],-1),o('<h1 id="小东西-1" tabindex="-1">小东西 <a class="header-anchor" href="#小东西-1" aria-label="Permalink to &quot;小东西&quot;">​</a></h1><p>▓▓▓▓<br> 【小东西】<br> C+1000<br> 独立随从</p><p>性别：无</p><p>年龄：约400岁（小东西的年龄分生前死后两个阶段，因生前卒年不详，故仅能得出400岁的大概数据）</p><p>体型：1</p><p>种族：被附魔的断手</p><p>语言：手语 英语</p><p>相貌：这是一只苍白的右手，手背上布满伤疤及缝合后留下的痕迹。</p><p>性格：完全忠心于主人的随从，拥有极高的警惕性。</p><p>概述：小东西原本是蒂图斯·亚当斯的右手，在试图保护他的兄弟Goody的时候被约瑟夫·克拉克斯通残忍杀害。其兄弟Goody为了让他留在身边，通过巫术将其灵魂附在了这只断手上，使他以“小东西”的形式获得了永生。<br> 小东西需要休息，但无需呼吸、进食。小东西的感知方式为灵魂类的感应能力，类似于盲视并具有黑暗视觉及灵感视觉。</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量6<br> ■敏捷11<br> ■耐力6<br> ▓▓心智属性<br> ■智力6<br> ■感知11<br> ■决心9<br> ▓▓互动属性<br> ■风度6<br> ■操控11<br> ■沉着9</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动8<br> 专业：反射-8 攀爬-5<br> ■求生5<br> 专业：强韧-5<br> ■射击1<br> 专业：<br> ■武技5<br> 专业：拳-5</p><p>▓▓心智系<br> ■学识1<br> 专业：<br> ■器用1<br> 专业：<br> ■手艺1<br> 专业：<br> ■专注5<br> 专业：意志-5</p><p>▓▓互动系<br> ■洞察5<br> 专业：侦查-5<br> ■隐秘8<br> 专业：潜藏-8<br> ■表达1<br> 专业：<br> ■社交1<br> 专业</p><p>▓▓▓▓衍生属性值<br> ▓体积 1<br> ▓速度 24米<br> ▓先攻 20<br> ▓防御 11+2<br> ▓生命值 12<br> ▓意志力池 =20<br> ▓意志 20+3<br> ▓反射 31+5<br> ▓强韧 17+3<br> ▓侦查 25+6<br> ▓敏感范围 260米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的1DP增强加值与1点附加成功，可携带物品体积额外提升4点<br> 敏捷上的每1点附加成功会在回合开始时额外提供1点基础Ap并提高3米额外移速<br> 耐力上的每1点附加成功会为其提供5点额外的生命值</p><p>智力上的每1点附加成功会为其提供每场景一次，在进行某个检定时可以将1个失败骰转为成功骰的能力，每有2点智力附加成功就能额外将一个失败骰转为成功骰，这一能力不能在一次检定中多次使用<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升或者1点全检定上的机运加值，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与任意一种互动系技能的1点附加成功（选择洞察）<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰以及在进行短休息后额外恢复1点意志力</p><p>▓▓▓▓攻击预设：20+4</p><p>▓▓▓▓防御预设：<br> 防御上的附加成功与额外效果需要基于防御类型才能生效，若该防御类型为0，附加成功与额外效果均不生效。</p><p>基础防御： 11<br> 附加成功： 2<br> 额外效果：<br> 防御类型：<br> 附加成功：<br> 额外效果：</p><p>豁免项：<br> 意志豁免：20<br> 附加成功：3<br> 反射豁免：28<br> 附加成功：5<br> 强韧豁免：17<br> 附加成功：3</p><p>免疫项：</p><p>▓▓▓▓特性：</p><p>万能沟通：一只手能够做出的动作或许有限，但若这只手便是我的全部，我会将它开发到极限。小东西可以通过动作来传递信息和交流，它的肢体语言能表达最精细最全面的信息。同时他也能够读懂所有生物的肢体语言，并理解大多数正常生物的交流方式。</p><p>战斗技巧：小东西的全身视作拥有3L武器伤害的天生武器。</p><p>信息搜集：小东西尤为擅长窃听，监视以及情报提炼，同时又注重于隐藏自己，在进行潜藏和侦查检定时获得3dp的技艺加值。</p><p>开锁大师：小东西能够轻松打开各种门锁、手铐等。在调查阶段总能扮演一个强有力的助手。小东西在进行开锁和拆除装置检定时获得3dp的技艺加值。</p><p>高超机动：小东西长年穿梭于各种狭小的空间中，其超绝的机动性即便是巫术操纵的乌鸦也要甘拜下风。小东西在进行运动相关检定时获得3dp的技艺加值。<br> ▓▓▓▓装备位：<br> 小东西仅可以使用单手能够使用的装备，但若小东西进行了意念移物相关的强化，则可以不受限制地使用装备。</p><p>▓▓▓▓强化<br> 血统与训练：（小东西可以进行血统与训练强化，但血统与训练中所具有的技艺部分，小东西能使用的仅有与手部及灵魂相关的内容。小东西原本血统视为人类）</p><p>改造与功法：（小东西可以进行与手部及灵魂相关的改造）</p><p>能量池：（小东西能拥有的能量池数量符合等级规则）</p><p>技艺与称号：（小东西可以使用与手部及灵魂相关的技艺）</p><p>▓▓▓▓物品：</p><p>▓▓▓▓购买记录：</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',37)])])}const m=b(d,[["render",n]]);export{f as __pageData,m as default};
